#include <stdio.h>
#include <string.h>

int longest_palindrome_length(const char *s) {
    int freq[26] = {0};
    for (int i = 0; s[i] != '\0'; ++i) {
        freq[s[i] - 'a']++;
    }
    int length = 0;
    int odd = 0;
    for (int i = 0; i < 26; ++i) {
        length += (freq[i] / 2) * 2;
        if (freq[i] % 2) odd = 1;
    }
    return length + odd;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char s[101];
    getchar(); // consume newline after T
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(s, sizeof(s), stdin)) break;
        s[strcspn(s, "\n")] = '\0'; // remove trailing newline
        printf("%d\n", longest_palindrome_length(s));
    }
    return 0;
}

