import java.io.*;
import java.util.*;

public class Main {
    private static int longestPalindromeLength(String s) {
        int[] freq = new int[26];
        for (char c : s.toCharArray()) freq[c - 'a']++;
        int length = 0, odd = 0;
        for (int cnt : freq) {
            length += (cnt / 2) * 2;
            if (cnt % 2 == 1) odd = 1;
        }
        return length + odd;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; ++i) {
            String s = br.readLine();
            sb.append(longestPalindromeLength(s)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

def longest_palindrome_length(s: str) -> int:
    freq = [0] * 26
    for ch in s:
        freq[ord(ch) - ord('a')] += 1
    length = 0
    odd = 0
    for cnt in freq:
        length += (cnt // 2) * 2
        if cnt % 2:
            odd = 1
    return length + odd

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        out.append(str(longest_palindrome_length(data[i].strip())))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

